7	async function getFixtureIds(request: import('@playwright/test').APIRequestContext): Promise<{
8		nodeId: string;
9		projectId: string;
10		nodeName: string;
11		projectName: string;
12		projectPath: string;
13	}> {
14		const nodeResp = await request.post('/graphql', {
15			data: { query: '{ nodeInfo { id name } }' }
16		});
17		const nodeBody = (await nodeResp.json()) as { data: { nodeInfo: { id: string; name: string } } };
18		const projectsResp = await request.get('/api/projects');
19		const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
20		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
21		if (!fixture) {
22			throw new Error(
23				`fixture server has no ddx-e2e-* project registered (got: ${projects.map((p) => p.id).join(', ')})`
24			);
25		}
26		return {
27			nodeId: nodeBody.data.nodeInfo.id,
28			projectId: fixture.id,
29			nodeName: nodeBody.data.nodeInfo.name,
30			projectName: fixture.name,
31			projectPath: fixture.path
32		};
33	}
