// Story16RunDetailFullStackP95 — cross-cutting guard that the run-detail
// surface can be reached from the Runs list and that every tab (prompt,
// response, tools, evidence) renders and becomes interactive within one
// requestAnimationFrame after its mocked GraphQL payload resolves, even
// with the p95-shaped fixture of 200 tool calls and 30 evidence files.
test('Story16RunDetailFullStackP95', async ({ page }) => {
	const TOOL_COUNT = 200;
	const EVIDENCE_COUNT = 30;
	const toolCalls = Array.from({ length: TOOL_COUNT }, (_, index) => ({
		node: {
			id: `rtc-${index}`,
			seq: index,
			name: index % 2 === 0 ? 'Bash' : 'Read',
			inputs: JSON.stringify({ command: `echo step ${index}` }),
			output: `step-${index}-output`,
			error: null,
			durationMs: index + 1
		},
		cursor: `rtc-${index}`
	}));
	const evidenceFiles = Array.from({ length: EVIDENCE_COUNT }, (_, index) => ({
		path: `evidence/evidence-${String(index).padStart(2, '0')}.txt`,
		size: 512 + index,
		mimeType: 'text/plain'
	}));
	const evidenceContent = Object.fromEntries(
		evidenceFiles.map((file) => [
			file.path,
			{
				path: file.path,
				content: `evidence body for ${file.path}`,
				sizeBytes: file.size,
				truncated: false,
				mimeType: file.mimeType
			}
		])
	);

	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as {
			query: string;
			variables?: Record<string, unknown>;
		};

		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
			});
			return;
		}
		if (body.query.includes('ProjectsForLayout') || body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((node) => ({ node })) } } })
			});
			return;
		}
		if (body.query.includes('ProjectRuns')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						runs: {
							edges: [listRowFor(runNode)],
							pageInfo: { hasNextPage: false, endCursor: null },
							totalCount: 1
						}
					}
				})
			});
			return;
		}
		if (body.query.includes('ParentRunParent')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: null } })
			});
			return;
		}
		if (
			body.query.includes('RunHeader') ||
			body.query.includes('RunDetailExpand') ||
			body.query.includes('RunDetail') ||
			body.query.includes('RunExists')
		) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: runNode } })
			});
			return;
		}
		if (body.query.includes('RunExecutionExpand')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { execution: null } })
			});
			return;
		}
		if (body.query.includes('RunSessionExpand')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						agentSession: {
							id: 'sess-x',
							workerId: 'worker-run-001',
							harness: 'claude',
							model: 'claude-sonnet-4-6',
							cost: 0.0876,
							billingMode: 'usage',
							baseRev: 'abc123def',
							resultRev: 'def456abc',
							stdoutPath: '.ddx/agent-logs/agent-sess-x.jsonl',
							stderrPath: '.ddx/agent-logs/agent-sess-x.err',
							tokens: { prompt: 12000, completion: 3400, total: 15400, cached: 0 },
							status: 'completed',
							outcome: 'success',
							prompt: 'session prompt',
							response: 'session response',
							stderr: 'session stderr'
						}
					}
				})
			});
			return;
		}
		if (body.query.includes('RunToolCallsExpand')) {
			const after = body.variables?.['after'] as string | null | undefined;
			const afterIndex = after ? Number(after.split('-').pop() ?? '-1') : -1;
			const slice = toolCalls.slice(afterIndex + 1, afterIndex + 51);
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						runToolCalls: {
							edges: slice,
							pageInfo: {
								hasNextPage: afterIndex + slice.length < toolCalls.length - 1,
								endCursor: slice[slice.length - 1]?.cursor ?? null
							},
							totalCount: toolCalls.length
						}
					}
				})
			});
			return;
		}
		if (body.query.includes('RunEvidenceFiles')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						run: {
							id: RUN_ID,
							bundleFiles: evidenceFiles
						}
					}
				})
			});
			return;
		}
		if (body.query.includes('RunBundleFileFetch')) {
			const path = String(body.variables?.['path'] ?? '');
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { runBundleFile: evidenceContent[path] ?? null } })
			});
			return;
		}
		if (body.query.includes('ProducedArtifact')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { artifact: null } })
			});
			return;
		}
		await route.continue();
	});

	// Step 1: start at the Runs list (Story 16 entry point).
	await page.goto(`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/runs`);
	await expect(page.getByRole('heading', { name: 'Runs' })).toBeVisible();

	// Step 2: traverse from the list into /runs/[runId] for the p95 run.
	await page.locator(`a[href$="/runs/${RUN_ID}"]`).first().click();
	await expect(page).toHaveURL(new RegExp(`/runs/${RUN_ID}(\\?.*)?$`));

	const detail = page.locator('[data-testid="rundetail"]');
	await expect(detail).toBeVisible();
	await expect(detail.locator('button[data-tab="overview"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="prompt"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="response"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="tools"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="session"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="evidence"]')).toBeVisible();

	// nextFrameOk schedules an rAF after the most recent mocked GraphQL payload
	// has already resolved (the route handlers fulfill synchronously) and
	// returns true iff that single frame finished within the 100ms budget — if
	// the main thread were blocked beyond a single rAF, the wall-clock delta
	// would exceed that budget.
	const nextFrameOk = () =>
		page.evaluate(
			() =>
				new Promise<boolean>((resolve) => {
					const start = performance.now();
					requestAnimationFrame(() => resolve(performance.now() - start < 100));
				})
		);

	// Step 3: prompt tab — render + interactive in one rAF.
	await detail.locator('button[data-tab="prompt"]').click();
	await expect(detail.locator('[data-testid="rundetail-prompt-body"]')).toContainText(
		'session prompt'
	);
	expect(await nextFrameOk()).toBe(true);
	await expect(detail.locator('[data-active-tab]')).toHaveAttribute('data-active-tab', 'prompt');

	// Step 4: response tab.
	await detail.locator('button[data-tab="response"]').click();
	await expect(detail.locator('[data-testid="rundetail-response-body"]')).toContainText(
		'session response'
	);
	expect(await nextFrameOk()).toBe(true);
	await expect(detail.locator('[data-active-tab]')).toHaveAttribute('data-active-tab', 'response');

	// Step 5: tools tab — paginate through all 200 entries, with each
	// page-render finishing within a single rAF.
	await detail.locator('button[data-tab="tools"]').click();
	await expect(detail.locator('[data-testid="rundetail-tools"]')).toBeVisible();
	await expect(detail.locator('[data-tool-seq="0"]')).toBeVisible();
	expect(await nextFrameOk()).toBe(true);
	for (const seq of [50, 100, 150]) {
		await detail.getByRole('button', { name: 'Load more' }).click();
		await expect(detail.locator(`[data-tool-seq="${seq}"]`)).toBeVisible();
		expect(await nextFrameOk()).toBe(true);
	}
	await expect(detail.locator('[data-tool-seq="199"]')).toBeVisible();
	await expect(detail.locator('[data-testid="rundetail-tools"]')).toContainText(
		`${TOOL_COUNT} of ${TOOL_COUNT} tool calls`
	);
	await expect(detail.locator('[data-active-tab]')).toHaveAttribute('data-active-tab', 'tools');

	// Step 6: evidence tab — list all 30 files; inline-view the first.
	await detail.locator('button[data-tab="evidence"]').click();
	await expect(detail.locator('[data-testid="rundetail-evidence"]')).toBeVisible();
	await expect(detail.locator('[data-evidence-path]')).toHaveCount(EVIDENCE_COUNT);
	await expect(detail.locator('[data-evidence-path="evidence/evidence-29.txt"]')).toBeVisible();
	expect(await nextFrameOk()).toBe(true);
	const firstEvidenceView = detail.locator('[data-evidence-view="evidence/evidence-00.txt"]');
	await firstEvidenceView.click();
	await expect(firstEvidenceView).toHaveText('Hide');
	await expect(detail.locator('[data-testid="evidence-inline"]')).toBeVisible();
	await expect(detail.locator('[data-testid="evidence-inline-content"]')).toContainText(
		'evidence body for evidence/evidence-00.txt'
	);
	expect(await nextFrameOk()).toBe(true);
	await expect(detail.locator('[data-active-tab]')).toHaveAttribute('data-active-tab', 'evidence');
});

// TestStory16RunDetailP95FixtureShape pins the Go-side fixture and resolver
// shape that the Story 16 Playwright p95 flow asserts in the browser: the
// run-tool-call resolver must surface exactly 200 ToolCalls (in stable seq
// order) and the bundle-files lister must surface exactly 30 evidence files
// (in path-sorted order with mimeType populated) for the same run.
func TestStory16RunDetailP95FixtureShape(t *testing.T) {
	const toolCount = 200
	const evidenceCount = 30

	workDir := t.TempDir()
	writeConfig(t, workDir, `version: "1.0"`+"\n")
	state := stateWithProject(workDir)

	bundleID := "20260502T120000-p95shape"
	bundleDir := filepath.Join(workDir, agent.ExecuteBeadArtifactDir, bundleID)
	if err := os.MkdirAll(filepath.Join(bundleDir, "evidence"), 0o755); err != nil {
		t.Fatal(err)
	}
	for i := 0; i < evidenceCount; i++ {
		name := filepath.Join("evidence", "evidence-"+leftPad2(i)+".txt")
		body := []byte("evidence body for " + name)
		if err := os.WriteFile(filepath.Join(bundleDir, name), body, 0o644); err != nil {
			t.Fatal(err)
		}
	}

	toolCalls := make([]agent.ToolCallEntry, toolCount)
	for i := 0; i < toolCount; i++ {
		toolCalls[i] = agent.ToolCallEntry{
			Tool:     map[bool]string{true: "Bash", false: "Read"}[i%2 == 0],
			Input:    `{"command":"echo step ` + strconv.Itoa(i) + `"}`,
			Output:   "step-" + strconv.Itoa(i) + "-output",
			Duration: i + 1,
		}
	}
	now := time.Date(2026, 5, 2, 12, 0, 0, 0, time.UTC)
	entry := agent.SessionIndexEntry{
		ID:          "sess-p95-001",
		Harness:     "claude",
		BillingMode: "paid",
		StartedAt:   now,
		BundlePath:  filepath.ToSlash(filepath.Join(agent.ExecuteBeadArtifactDir, bundleID)),
		ToolCalls:   toolCalls,
	}
	if err := agent.AppendSessionIndex(agent.SessionLogDirForWorkDir(workDir), entry, now); err != nil {
		t.Fatal(err)
	}

	calls := state.GetRunToolCallsGraphQL(entry.ID)
	if len(calls) != toolCount {
		t.Fatalf("GetRunToolCallsGraphQL: got %d calls, want %d", len(calls), toolCount)
	}
	for i, c := range calls {
		if c.Seq != i {
			t.Fatalf("calls[%d].Seq=%d, want %d", i, c.Seq, i)
		}
		if c.ID != "rtc-"+strconv.Itoa(i) {
			t.Fatalf("calls[%d].ID=%s, want rtc-%d", i, c.ID, i)
		}
	}
	if calls[0].Tool != "Bash" || calls[1].Tool != "Read" || calls[toolCount-1].Tool != "Read" {
		t.Fatalf("tool-call name pattern broken: [0]=%s [1]=%s [last]=%s",
			calls[0].Tool, calls[1].Tool, calls[toolCount-1].Tool)
	}

	files := listRunBundleFiles(bundleDir)
	if len(files) != evidenceCount {
		t.Fatalf("listRunBundleFiles: got %d files, want %d", len(files), evidenceCount)
	}
	for i, f := range files {
		want := "evidence/evidence-" + leftPad2(i) + ".txt"
		if f.Path != want {
			t.Fatalf("files[%d].Path=%s, want %s", i, f.Path, want)
		}
		if f.MimeType != "text/plain" {
			t.Fatalf("files[%d].MimeType=%s, want text/plain", i, f.MimeType)
		}
		if f.Size == 0 {
			t.Fatalf("files[%d].Size=0, want non-zero", i)
		}
	}
}

func leftPad2(n int) string {
	if n < 10 {
		return "0" + strconv.Itoa(n)
	}
	return strconv.Itoa(n)
}

